// Draft review report (generated by DeepSeek)
// Nightly job use, provider locked to deepseek-chat, cost-controlled

import * as fs from 'node:fs';
import * as path from 'node:path';
import { fileURLToPath } from 'node:url';
import { estimateDeepSeekCost } from './cost-guard.js';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_DIR = path.resolve(__dirname, '..', '..');
const REVIEW_DIR = path.join(PROJECT_DIR, '.eastmoney-ai', 'reviews');

function ensureReviewDir() {
  if (!fs.existsSync(REVIEW_DIR)) fs.mkdirSync(REVIEW_DIR, { recursive: true });
}

/**
 * 按维度分组统计
 * @param {Array} evaluations
 * @param {Array} historyEntries — 反查原始 prompt/analysis
 * @returns {{ stats: object, topFailures: Array }}
 */
export function computeStats(evaluations) {
  const groups = {}; // key: "template:model:mode:backtest:thinking"

  for (const ev of evaluations) {
    const key = [
      ev.template || '?',
      ev.model || '?',
      ev.mode || 'single',
      ev.enableSelfBacktest ? 'bt' : 'nobt',
      ev.enableThinking ? 'think' : 'nothink',
    ].join(':');

    if (!groups[key]) {
      groups[key] = {
        template: ev.template, model: ev.model, mode: ev.mode,
        enableSelfBacktest: ev.enableSelfBacktest, enableThinking: ev.enableThinking,
        total: 0, correct: 0, strongCorrect: 0, wrong: 0, alphaSum: 0,
      };
    }
    const g = groups[key];
    g.total++;
    if (ev.verdict === 'strong_correct') g.strongCorrect++;
    if (ev.verdict === 'strong_correct' || ev.verdict === 'correct') g.correct++;
    if (ev.verdict === 'wrong') g.wrong++;
    if (ev.alpha != null) g.alphaSum += ev.alpha;
  }

  const stats = Object.values(groups).map((g) => ({
    ...g,
    accuracy: g.total > 0 ? +(g.correct / g.total * 100).toFixed(1) : 0,
    avgAlpha: g.total > 0 ? +(g.alphaSum / g.total).toFixed(2) : 0,
  })).sort((a, b) => b.total - a.total);

  return { stats, groups };
}

/**
 * Pick top N severe failure cases
 * @param {Array} evaluations
 * @param {Array} historyEntries
 * @param {number} n
 * @returns {Array}
 */
export function pickFailureCases(evaluations, historyEntries, n = 5) {
  const historyMap = new Map();
  for (const h of historyEntries) {
    historyMap.set(h.id || h.timestamp, h);
  }

  return evaluations
    .filter((ev) => ev.verdict === 'wrong' && ev.alpha != null && Math.abs(ev.alpha) > 10)
    .sort((a, b) => Math.abs(b.alpha || 0) - Math.abs(a.alpha || 0))
    .slice(0, n)
    .map((ev) => {
      const h = historyMap.get(ev.historyId) || {};
      return {
        code: ev.code,
        template: ev.template,
        judgment: ev.judgment,
        alpha: ev.alpha,
        stockReturn: ev.stockReturn,
        promptSnippet: String(h.prompt || '').slice(0, 500),
        analysisSnippet: String(h.analysis || '').slice(0, 500),
      };
    });
}

/**
 * Generate draft review report
 * @param {object} opts
 * @param {Array} opts.evaluations
 * @param {Array} opts.historyEntries
 * @param {Function} opts.callDeepSeek — (prompt) => { text, usage }
 * @param {Function} opts.recordSpending
 * @returns {{ draftPath: string, cost: number }}
 */
export async function generateDraftReview(opts) {
  const { evaluations, historyEntries, callDeepSeek, recordSpending } = opts;

  const { stats } = computeStats(evaluations);
  const failures = pickFailureCases(evaluations, historyEntries, 5);

  // 拼统计数据
  let statsMd = '| 分组 | 样本 | 准确率 | 平均 alpha |\n|------|------|--------|-----------|\n';
  for (const s of stats) {
    const key = [s.template, s.model, s.mode, s.enableSelfBacktest ? '回测' : '', s.enableThinking ? '思考' : ''].filter(Boolean).join('/');
    statsMd += `| ${key} | ${s.total} | ${s.accuracy}% | ${s.avgAlpha} |\n`;
  }

  let failuresMd = '';
  for (const f of failures) {
    failuresMd += `### ${f.code} | ${f.template} | 判断:${f.judgment}\n\n`;
    failuresMd += `- alpha: ${f.alpha}% | 实际涨跌: ${f.stockReturn}%\n`;
    failuresMd += `- prompt 摘要: ${f.promptSnippet}\n`;
    failuresMd += `- 分析摘要: ${f.analysisSnippet}\n\n`;
  }

  const prompt = `你正在协助迭代一只 A 股月线分析工具。基于以下数据，生成一份诊断草稿。

要求：
1. 用具体数字描述各模板/模型/模式的准确率差异
2. 失误案例的共性是什么（措辞 / 模型能力 / 数据维度）
3. 提出 3-5 条具体改进建议，按优先级排序，每条：
   - 改什么（prompt 措辞、模板内容、数据补充、模型路由）
   - 为什么（引用具体数据）
   - 预期改善

【统计数据】
${statsMd}

【严重失误案例】
${failuresMd}

注意：本草稿将由用户审核，通过的建议会送 Claude Opus 精修。所以你只需要给出基于数据的诊断，不需要给最终改动代码。`;

  const result = await callDeepSeek(prompt);
  const cost = result.usage
    ? estimateDeepSeekCost(result.usage.inputTokens, result.usage.outputTokens, 'deepseek-chat')
    : 0;

  if (recordSpending) recordSpending(cost);

  const today = new Date().toISOString().slice(0, 10);
  const draftPath = path.join(REVIEW_DIR, `draft-${today}.md`);

  ensureReviewDir();
  const content = `# 草稿复盘 ${today}

> 由 DeepSeek 自动生成，需要用户审核后才能进入精修阶段

## 评估摘要
- 总样本：${evaluations.length} 条
- 本次草稿成本：¥${cost.toFixed(4)}
- 月度累计：见 budget.json

## 统计数据
${statsMd}

## 失误案例（top 5）
${failuresMd}

## DeepSeek 诊断建议
${result.text}

## 用户审核区
${generateChecklist(result.text)}
`;

  fs.writeFileSync(draftPath, content, 'utf-8');
  return { draftPath, cost };
}

function generateChecklist(llmText) {
  // 从 LLM 输出中提取建议编号
  const suggestions = llmText.match(/\d+\.\s*[（(]?[^）)\n]+[）)]?.*?(?=\n\d+\.|\n*$)/gs) || [];
  if (suggestions.length === 0) return '- [ ] 无建议\n';
  return suggestions.map((s, i) => {
    const title = s.replace(/\n/g, ' ').slice(0, 80);
    return `- [ ] 建议 ${i + 1}：${title}... [ 通过 / 拒绝 / 修改 ]`;
  }).join('\n');
}
